# Property-based tests: invariants that must hold for ALL inputs
from hypothesis import given, settings, strategies as st
import openai, re, pytest

client = openai.OpenAI()
SYSTEM = open("prompts/classifier.txt").read()

VALID_LABELS = {"positive", "negative", "neutral"}

@given(text=st.text(min_size=10, max_size=200))
@settings(max_examples=30, deadline=10_000)
def test_classifier_always_returns_valid_label(text: str):
    """Sentiment classifier must ALWAYS return one of the valid labels."""
    resp = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {"role": "system", "content": SYSTEM},
            {"role": "user", "content": text},
        ],
        temperature=0,
    )
    output = resp.choices[0].message.content.strip().lower()
    assert output in VALID_LABELS, f"Invalid label '{output}' for input: {text[:50]}"

@given(n=st.integers(min_value=1, max_value=10))
@settings(max_examples=20)
def test_list_generator_returns_exactly_n_items(n: int):
    """List generator must return exactly N items regardless of N."""
    from prompts import generate_list
    items = generate_list(topic="fruits", count=n)
    assert len(items) == n, f"Expected {n} items, got {len(items)}"
